import React, { useState } from "react";
import './Logout.css';
import './Welcome';
import { useNavigate } from "react-router";
import axios from "axios";
function Logout () {
    const [response, setResponse] = useState([]); 
    const navigate = useNavigate();
    const GetCall = (prop) => {
       return axios.get(`http://localhost:8080/user/${prop.userName}/items`).then(response => setResponse(response.data))
    }
    return response;
